def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
  val n = nums.length
  val ans = Array.ofDim[Long](queries.length)

  for (i <- queries.indices) {
    val (li, ri, threshold) = (queries(i)(0), queries(i)(1), queries(i)(2))
    val freq = scala.collection.mutable.HashMap[Long, Int]()
    var best: Long = -1

    for (j <- li to ri) {
      val num = nums(j)
      if (j > li) {
        val prevNum = nums(j - 1)
        freq(prevNum) -= 1
        if (freq(prevNum) == 0) freq.remove(prevNum)
      }
      freq(num) = freq.getOrElse(num, 0) + 1
      if (freq(num) >= threshold) {
        if (best == -1 || freq(num) > freq(best) || (freq(num) == freq(best) && num < best)) {
          best = num
        }
      }
    }
    ans(i) = best
  }

  ans
}
